## Comprehensive Testing Strategy

### Unit Tests
\`\`\`rust
#[cfg(test)]
mod tests {
    use super::*;
    use smallvec::SmallVec;

    /// SmallVec stays on stack for small sizes
    #[test]
    fn test_small_stays_on_stack() {
        let tokens: TokenList = smallvec![
            Token::from("hello"),
            Token::from("world"),
        ];

        // Check it's inline (not spilled to heap)
        assert!(!tokens.spilled());
        assert_eq!(tokens.len(), 2);
    }

    /// SmallVec spills to heap when exceeding capacity
    #[test]
    fn test_large_spills_to_heap() {
        let mut tokens: TokenList = SmallVec::new();

        // Add more than inline capacity
        for i in 0..10 {
            tokens.push(Token::from(format!("token{}", i).as_str()));
        }

        // Should have spilled to heap
        assert!(tokens.spilled());
        assert_eq!(tokens.len(), 10);
    }

    /// SmallVec works with iteration
    #[test]
    fn test_iteration() {
        let filters: FilterList = smallvec![
            Filter::Agent("claude".into()),
            Filter::Days(7),
        ];

        let count = filters.iter().count();
        assert_eq!(count, 2);

        // For loop works
        for filter in &filters {
            assert!(matches!(filter, Filter::Agent(_) | Filter::Days(_)));
        }
    }

    /// Empty SmallVec works correctly
    #[test]
    fn test_empty() {
        let tokens: TokenList = SmallVec::new();

        assert!(tokens.is_empty());
        assert!(!tokens.spilled());
        assert_eq!(tokens.len(), 0);
    }

    /// SmallVec can be converted to Vec
    #[test]
    fn test_into_vec() {
        let tokens: TokenList = smallvec![Token::from("test")];
        let vec: Vec<Token> = tokens.into_vec();

        assert_eq!(vec.len(), 1);
    }

    /// SmallVec implements common traits
    #[test]
    fn test_traits() {
        let mut tokens: TokenList = SmallVec::new();

        // Push/pop
        tokens.push(Token::from("a"));
        assert_eq!(tokens.pop(), Some(Token::from("a")));

        // Extend
        tokens.extend([Token::from("b"), Token::from("c")]);
        assert_eq!(tokens.len(), 2);

        // Clear
        tokens.clear();
        assert!(tokens.is_empty());
    }

    /// Correct inline capacity
    #[test]
    fn test_inline_capacity() {
        let tokens: TokenList = SmallVec::new();
        assert_eq!(tokens.inline_size(), 4);

        let filters: FilterList = SmallVec::new();
        assert_eq!(filters.inline_size(), 2);

        let highlights: HighlightList = SmallVec::new();
        assert_eq!(highlights.inline_size(), 4);
    }
}
