### Statistical Distribution Tests
\`\`\`rust
/// Verify chosen sizes match real-world distributions
#[test]
fn test_token_distribution() {
    // Sample real queries and count tokens
    let queries = [
        "rust programming",           // 2 tokens
        "how to implement search",    // 4 tokens
        "debug error",                // 2 tokens
        "optimize performance rust",  // 3 tokens
        "a",                          // 1 token
    ];

    let mut token_counts = vec![];
    for query in queries {
        let tokens: TokenList = tokenize(query);
        token_counts.push(tokens.len());

        // Most should not spill (inline capacity = 4)
        if tokens.len() <= 4 {
            assert!(!tokens.spilled(), "Query '{}' spilled unexpectedly", query);
        }
    }

    // Calculate statistics
    let avg = token_counts.iter().sum::<usize>() as f64 / token_counts.len() as f64;
    let max = *token_counts.iter().max().unwrap();

    println!("Token distribution: avg={:.1}, max={}", avg, max);

    // Our inline size (4) should cover >95% of cases
    let covered = token_counts.iter().filter(|&&c| c <= 4).count();
    let coverage = covered as f64 / token_counts.len() as f64;

    assert!(coverage >= 0.95, "Inline size should cover 95%+ of cases");
}

/// Profile real filter usage
#[test]
fn test_filter_distribution() {
    // Typical filter combinations
    let filter_sets = [
        vec![Filter::Agent("claude".into())],                    // 1 filter
        vec![Filter::Agent("claude".into()), Filter::Days(7)],   // 2 filters
        vec![Filter::Days(30)],                                  // 1 filter
        vec![],                                                  // 0 filters
    ];

    for filters in filter_sets {
        let list: FilterList = filters.into_iter().collect();

        // Should never spill (inline capacity = 2)
        assert!(!list.spilled());
    }
}
