use proptest::prelude::*;

proptest! {
    /// Property: SmallVec behaves like Vec
    #[test]
    fn prop_smallvec_vec_equivalence(items in prop::collection::vec(0u32..1000, 0..20)) {
        let vec: Vec<u32> = items.clone();
        let smallvec: SmallVec<[u32; 4]> = items.into_iter().collect();

        prop_assert_eq!(vec.len(), smallvec.len());
        prop_assert_eq!(vec.is_empty(), smallvec.is_empty());

        for (v, s) in vec.iter().zip(smallvec.iter()) {
            prop_assert_eq!(v, s);
        }
    }

    /// Property: spilled iff len > inline_capacity
    #[test]
    fn prop_spill_threshold(len in 0usize..20) {
        let mut sv: SmallVec<[u32; 4]> = SmallVec::new();
        for i in 0..len {
            sv.push(i as u32);
        }

        let should_spill = len > 4;
        prop_assert_eq!(sv.spilled(), should_spill);
    }
}
