### Benchmark
\`\`\`rust
use criterion::{BenchmarkId, Criterion, criterion_group, criterion_main};

fn bench_collection_allocation(c: &mut Criterion) {
    let mut group = c.benchmark_group("collection_alloc");

    for size in [1, 2, 3, 4, 5, 8, 16] {
        group.bench_with_input(
            BenchmarkId::new("vec", size),
            &size,
            |b, &size| {
                b.iter(|| {
                    let mut v: Vec<u32> = Vec::new();
                    for i in 0..size {
                        v.push(i);
                    }
                    v
                })
            },
        );

        group.bench_with_input(
            BenchmarkId::new("smallvec", size),
            &size,
            |b, &size| {
                b.iter(|| {
                    let mut v: SmallVec<[u32; 4]> = SmallVec::new();
                    for i in 0..size {
                        v.push(i);
                    }
                    v
                })
            },
        );
    }

    group.finish();
}

fn bench_tokenization(c: &mut Criterion) {
    let queries = [
        "short",
        "two words",
        "three word query",
        "this has four tokens",
        "five tokens in this query",
    ];

    c.bench_function("tokenize_vec", |b| {
        b.iter(|| {
            for query in &queries {
                let _: Vec<Token> = tokenize_vec(query);
            }
        })
    });

    c.bench_function("tokenize_smallvec", |b| {
        b.iter(|| {
            for query in &queries {
                let _: TokenList = tokenize(query);
            }
        })
    });
}
